const SecureKeyManager = {
  MASTER_KEY_STORAGE_KEY: '@secure_master_key',
  
  generateMasterKey: async () => {
    const key = CryptoUtils.generateSecureRandom(32);
    const keyBase64 = CryptoUtils.arrayBufferToBase64(key);
    await AsyncStorage.setItem(SecureKeyManager.MASTER_KEY_STORAGE_KEY, keyBase64);
    return key;
  },

  getMasterKey: async () => {
    try {
      const keyBase64 = await AsyncStorage.getItem(SecureKeyManager.MASTER_KEY_STORAGE_KEY);
      if (keyBase64) {
        return CryptoUtils.base64ToArrayBuffer(keyBase64);
      }
      return await SecureKeyManager.generateMasterKey();
    } catch (error) {
      console.error('Error retrieving master key:', error);
      return await SecureKeyManager.generateMasterKey();
    }
  },

  deriveKey: async (masterKey, salt, info) => {
    const saltBuffer = typeof salt === 'string' 
      ? CryptoUtils.stringToArrayBuffer(salt) 
      : salt;
    const infoBuffer = typeof info === 'string' 
      ? CryptoUtils.stringToArrayBuffer(info) 
      : info;
    
    const prk = await HMAC_SHA256.hmac(saltBuffer, masterKey);
    
    const okm = await HMAC_SHA256.hmac(prk, new Uint8Array([...infoBuffer, 0x01]));
    
    return okm;
  },

  rotateKeys: async () => {
    const newKey = await SecureKeyManager.generateMasterKey();
    return newKey;
  }
};

